sp_widget.client_script:
function($scope, $location) {
    var c = this;

    // Navigate to persona-specific page
    c.navigateToPersona = function(personaId) {
        $location.path('/' + personaId);
    };

    // Hero quick actions
    c.heroAction = function(action) {
        switch(action) {
            case 'request_service':
                $location.path('/service_catalog');
                break;
            case 'deploy_app':
                // Redirect to service catalog with deployment focus
                $location.path('/service_catalog');
                break;
            case 'view_pipelines':
                // Redirect to developer workspace
                $location.path('/developer');
                break;
            case 'system_health':
                // Redirect to SRE workspace
                $location.path('/sre');
                break;
        }
    };

    // Quick links navigation
    c.quickLink = function(link) {
        switch(link) {
            case 'gitlab':
                // Redirect to developer workspace
                $location.path('/developer');
                break;
            case 'catalog':
                $location.path('/service_catalog');
                break;
            case 'api_explorer':
                // Redirect to developer workspace
                $location.path('/developer');
                break;
            case 'observability':
                // Redirect to SRE workspace
                $location.path('/sre');
                break;
        }
    };

    // View more in insights
    c.viewMore = function(type) {
        switch(type) {
            case 'deployments':
                // Redirect to developer workspace
                $location.path('/developer');
                break;
            case 'incidents':
                // Redirect to SRE workspace
                $location.path('/sre');
                break;
            case 'approvals':
                // Redirect to service catalog
                $location.path('/service_catalog');
                break;
            case 'security':
                // Redirect to security workspace
                $location.path('/security');
                break;
        }
    };

    // AI Assistant (placeholder)
    c.openAI = function() {
        // Future: Open AI assistant modal or panel
        alert('Platform AI Assistant - Coming Soon!');
    };
}

sp_widget.css:
/* IBM Carbon Design System - Home Page */
.idp-bob-home {
    background: var(--carbon-ui-background);
    min-height: 100vh;
}

/* Hero Section */
.idp-hero-section {
    background: linear-gradient(135deg, var(--carbon-ui-05) 0%, var(--carbon-ui-04) 100%);
    padding: var(--carbon-spacing-09) var(--carbon-spacing-06);
    margin-bottom: var(--carbon-spacing-07);
}

.idp-hero-content {
    max-width: 1200px;
    margin: 0 auto;
}

.idp-hero-welcome {
    color: var(--carbon-text-04);
    font-size: 2.5rem;
    font-weight: 300;
    margin-bottom: var(--carbon-spacing-03);
    font-family: 'IBM Plex Sans', sans-serif;
}

.idp-hero-subtitle {
    color: var(--carbon-text-04);
    font-size: 1.125rem;
    margin-bottom: var(--carbon-spacing-07);
    opacity: 0.9;
}

.idp-hero-actions {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: var(--carbon-spacing-05);
    max-width: 900px;
}

.idp-hero-btn {
    background: var(--carbon-interactive-01);
    color: var(--carbon-text-04);
    border: none;
    padding: var(--carbon-spacing-05);
    border-radius: 0;
    cursor: pointer;
    transition: background 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
    text-align: left;
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-04);
}

.idp-hero-btn:hover {
    background: var(--carbon-hover-primary);
}

.idp-hero-btn i {
    font-size: 1.5rem;
}

.idp-hero-btn-text {
    display: flex;
    flex-direction: column;
}

.idp-hero-btn-title {
    font-weight: 600;
    font-size: 1rem;
}

.idp-hero-btn-desc {
    font-size: 0.75rem;
    opacity: 0.8;
}

/* Main Content */
.idp-main-content {
    max-width: 1584px;
    margin: 0 auto;
    padding: 0 var(--carbon-spacing-06);
}

/* Persona Tiles */
.idp-persona-section {
    margin-bottom: var(--carbon-spacing-09);
}

.idp-section-title {
    color: var(--carbon-text-01);
    font-size: 1.75rem;
    font-weight: 400;
    margin-bottom: var(--carbon-spacing-06);
    font-family: 'IBM Plex Sans', sans-serif;
}

.idp-persona-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: var(--carbon-spacing-05);
}

.idp-persona-tile {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    padding: var(--carbon-spacing-06);
    cursor: pointer;
    transition: all 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
    position: relative;
}

.idp-persona-tile:hover {
    background: var(--carbon-hover-ui);
    border-color: var(--carbon-interactive-01);
    transform: translateY(-2px);
    box-shadow: 0 4px 8px rgba(0,0,0,0.1);
}

.idp-persona-tile-icon {
    font-size: 2rem;
    color: var(--carbon-interactive-01);
    margin-bottom: var(--carbon-spacing-04);
}

.idp-persona-tile-title {
    color: var(--carbon-text-01);
    font-size: 1.125rem;
    font-weight: 600;
    margin-bottom: var(--carbon-spacing-03);
}

.idp-persona-tile-desc {
    color: var(--carbon-text-02);
    font-size: 0.875rem;
    line-height: 1.5;
}

/* Insights Panel */
.idp-insights-section {
    margin-bottom: var(--carbon-spacing-09);
}

.idp-insights-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: var(--carbon-spacing-05);
}

.idp-insight-card {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    padding: var(--carbon-spacing-05);
}

.idp-insight-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: var(--carbon-spacing-05);
    padding-bottom: var(--carbon-spacing-04);
    border-bottom: 1px solid var(--carbon-ui-03);
}

.idp-insight-title {
    color: var(--carbon-text-01);
    font-size: 1rem;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.idp-insight-count {
    background: var(--carbon-interactive-01);
    color: var(--carbon-text-04);
    padding: 2px 8px;
    border-radius: 12px;
    font-size: 0.75rem;
    font-weight: 600;
}

.idp-insight-items {
    display: flex;
    flex-direction: column;
    gap: var(--carbon-spacing-04);
}

.idp-insight-item {
    padding: var(--carbon-spacing-03);
    background: var(--carbon-ui-background);
    border-left: 3px solid var(--carbon-ui-03);
    transition: border-color 0.11s;
}

.idp-insight-item:hover {
    border-left-color: var(--carbon-interactive-01);
}

.idp-insight-item-title {
    color: var(--carbon-text-01);
    font-size: 0.875rem;
    font-weight: 500;
    margin-bottom: var(--carbon-spacing-02);
}

.idp-insight-item-meta {
    color: var(--carbon-text-02);
    font-size: 0.75rem;
}

.idp-insight-view-more {
    margin-top: var(--carbon-spacing-04);
    color: var(--carbon-interactive-01);
    font-size: 0.875rem;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: var(--carbon-spacing-02);
}

.idp-insight-view-more:hover {
    text-decoration: underline;
}

/* AI Assistant Widget */
.idp-ai-section {
    margin-bottom: var(--carbon-spacing-09);
}

.idp-ai-widget {
    background: linear-gradient(135deg, #0f62fe 0%, #0043ce 100%);
    padding: var(--carbon-spacing-07);
    color: white;
    position: relative;
    overflow: hidden;
}

.idp-ai-widget::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -10%;
    width: 300px;
    height: 300px;
    background: rgba(255,255,255,0.1);
    border-radius: 50%;
}

.idp-ai-content {
    position: relative;
    z-index: 1;
}

.idp-ai-title {
    font-size: 1.5rem;
    font-weight: 600;
    margin-bottom: var(--carbon-spacing-03);
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.idp-ai-desc {
    font-size: 1rem;
    margin-bottom: var(--carbon-spacing-05);
    opacity: 0.9;
}

.idp-ai-btn {
    background: white;
    color: #0f62fe;
    border: none;
    padding: var(--carbon-spacing-04) var(--carbon-spacing-06);
    font-weight: 600;
    cursor: pointer;
    transition: transform 0.11s;
}

.idp-ai-btn:hover {
    transform: scale(1.05);
}

/* Quick Links */
.idp-quicklinks-section {
    margin-bottom: var(--carbon-spacing-09);
}

.idp-quicklinks-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: var(--carbon-spacing-05);
}

.idp-quicklink-card {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    padding: var(--carbon-spacing-05);
    cursor: pointer;
    transition: all 0.11s;
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-04);
}

.idp-quicklink-card:hover {
    background: var(--carbon-hover-ui);
    border-color: var(--carbon-interactive-01);
}

.idp-quicklink-icon {
    font-size: 1.5rem;
    color: var(--carbon-interactive-01);
}

.idp-quicklink-text {
    flex: 1;
}

.idp-quicklink-title {
    color: var(--carbon-text-01);
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: var(--carbon-spacing-02);
}

.idp-quicklink-desc {
    color: var(--carbon-text-02);
    font-size: 0.75rem;
}

/* Status Badges */
.status-badge {
    display: inline-block;
    padding: 2px 8px;
    border-radius: 2px;
    font-size: 0.75rem;
    font-weight: 600;
}

.status-success {
    background: #24a148;
    color: white;
}

.status-warning {
    background: #f1c21b;
    color: black;
}

.status-error {
    background: #da1e28;
    color: white;
}

.status-info {
    background: #0f62fe;
    color: white;
}

/* Responsive */
@media (max-width: 768px) {
    .idp-hero-actions {
        grid-template-columns: 1fr;
    }

    .idp-persona-grid,
    .idp-insights-grid,
    .idp-quicklinks-grid {
        grid-template-columns: 1fr;
    }
}

sp_widget.script:
(function() {
    // Get user information
    data.user = gs.getUser();
    data.userName = data.user.getDisplayName();
    data.userFirstName = data.user.getFirstName() || data.userName;

    // Get user roles
    var roles = gs.getUser().getRoles().toString().split(',');
    data.userRoles = roles;

    // Determine primary persona and welcome message
    data.primaryPersona = 'Application Developer'; // default
    data.personaIcon = 'fa-code';

    if (roles.indexOf('x_ibmin_idpbob.servicenow_admin') > -1) {
        data.primaryPersona = 'ServiceNow Administrator';
        data.personaIcon = 'fa-cog';
    } else if (roles.indexOf('x_ibmin_idpbob.platform_engineer') > -1) {
        data.primaryPersona = 'Platform Engineer';
        data.personaIcon = 'fa-server';
    } else if (roles.indexOf('x_ibmin_idpbob.sre') > -1) {
        data.primaryPersona = 'Site Reliability Engineer';
        data.personaIcon = 'fa-heartbeat';
    } else if (roles.indexOf('x_ibmin_idpbob.security_engineer') > -1) {
        data.primaryPersona = 'Security Engineer';
        data.personaIcon = 'fa-shield';
    } else if (roles.indexOf('x_ibmin_idpbob.product_owner') > -1) {
        data.primaryPersona = 'Product Owner';
        data.personaIcon = 'fa-users';
    }

    // Persona tiles with role-based visibility
    data.personaTiles = [];

    if (roles.indexOf('x_ibmin_idpbob.application_developer') > -1 || roles.length === 0) {
        data.personaTiles.push({
            id: 'developer',
            title: 'Developer Workspace',
            icon: 'fa-code',
            description: 'Build and deploy applications with ease'
        });
    }

    if (roles.indexOf('x_ibmin_idpbob.platform_engineer') > -1) {
        data.personaTiles.push({
            id: 'platform',
            title: 'Platform Engineering Console',
            icon: 'fa-server',
            description: 'Manage infrastructure and platform services'
        });
    }

    if (roles.indexOf('x_ibmin_idpbob.sre') > -1) {
        data.personaTiles.push({
            id: 'sre',
            title: 'SRE Command Center',
            icon: 'fa-heartbeat',
            description: 'Ensure reliability and performance'
        });
    }

    if (roles.indexOf('x_ibmin_idpbob.security_engineer') > -1) {
        data.personaTiles.push({
            id: 'security',
            title: 'Security & Compliance Hub',
            icon: 'fa-shield',
            description: 'Manage security and compliance'
        });
    }

    if (roles.indexOf('x_ibmin_idpbob.product_owner') > -1) {
        data.personaTiles.push({
            id: 'product',
            title: 'Product Demand Portal',
            icon: 'fa-users',
            description: 'Oversee product development and delivery'
        });
    }

    // Show all tiles if admin
    if (roles.indexOf('x_ibmin_idpbob.servicenow_admin') > -1) {
        data.personaTiles = [
            {id: 'developer', title: 'Developer Workspace', icon: 'fa-code', description: 'Build and deploy applications'},
            {id: 'platform', title: 'Platform Engineering Console', icon: 'fa-server', description: 'Manage infrastructure'},
            {id: 'sre', title: 'SRE Command Center', icon: 'fa-heartbeat', description: 'Ensure reliability'},
            {id: 'security', title: 'Security & Compliance Hub', icon: 'fa-shield', description: 'Manage security'},
            {id: 'product', title: 'Product Demand Portal', icon: 'fa-users', description: 'Oversee development'}
        ];
    }

    // Recent Deployments (mock data - replace with actual queries)
    data.recentDeployments = [
        {name: 'payment-service v2.3.1', status: 'success', time: '5 minutes ago', env: 'Production'},
        {name: 'user-api v1.8.0', status: 'success', time: '23 minutes ago', env: 'Staging'},
        {name: 'frontend-app v3.1.0', status: 'in_progress', time: '1 hour ago', env: 'Production'}
    ];

    // Active Incidents (mock data)
    data.activeIncidents = [
        {number: 'INC0001234', title: 'API Gateway High Latency', priority: 'P1', assignee: 'SRE Team'},
        {number: 'INC0001235', title: 'Database Connection Pool', priority: 'P2', assignee: 'Platform Team'}
    ];

    // Approval Queue (mock data)
    data.approvalQueue = [
        {type: 'Change Request', title: 'Production Deployment - payment-service', requester: 'John Doe', age: '2 hours'},
        {type: 'Access Request', title: 'Production Database Access', requester: 'Jane Smith', age: '4 hours'},
        {type: 'Infrastructure', title: 'New Kubernetes Cluster', requester: 'Platform Team', age: '1 day'}
    ];

    // Security Findings (mock data)
    data.securityFindings = [
        {severity: 'critical', title: 'SQL Injection Vulnerability', component: 'user-api', age: '1 day'},
        {severity: 'high', title: 'Outdated Dependencies', component: 'frontend-app', age: '3 days'}
    ];

    // Counts for badges
    data.deploymentCount = data.recentDeployments.length;
    data.incidentCount = data.activeIncidents.length;
    data.approvalCount = data.approvalQueue.length;
    data.securityCount = data.securityFindings.length;

})();
